{
  "name": "SmartMolding Downtime Tracker",
  "description": "A professional manufacturing application for tracking, recording, and analyzing downtime for CLF and JAD injection molding machines.",
  "requestFramePermissions": []
}

export enum MachineBrand {
  CLF = 'CLF',
  JAD = 'JAD'
}

export enum MachineStatus {
  RUNNING = 'RUNNING',
  STOPPED = 'STOPPED',
  MAINTENANCE = 'MAINTENANCE'
}

export enum Role {
  OPERATOR = 'OPERATOR',
  TEAM_LEADER = 'TEAM_LEADER',
  MAINTENANCE = 'MAINTENANCE',
  MANAGER = 'MANAGER'
}

export interface Machine {
  id: string;
  code: string;
  brand: MachineBrand;
  capacity: number;
  status: MachineStatus;
  currentDowntimeReason?: string;
}

export interface DowntimeEvent {
  id: string;
  machineId: string;
  startTime: number;
  endTime?: number;
  reason: string;
  description?: string;
  confirmedBy?: string;
  maintenanceNotes?: string;
  category: string;
}

export const DOWNTIME_REASONS = [
  { category: 'Lỗi Máy', reasons: ['Thủy lực', 'Hệ thống điện', 'Cảm biến (Sensor)', 'Robot/Tay gắp'] },
  { category: 'Khuôn', reasons: ['Kẹt khuôn', 'Bavia', 'Chỉnh khuôn/Vệ sinh'] },
  { category: 'Nguyên liệu', reasons: ['Thiếu liệu', 'Ẩm liệu', 'Tắc liệu'] },
  { category: 'Vận hành', reasons: ['Chất lượng SP', 'Thiếu nhân sự', 'Chờ QC'] },
  { category: 'Hệ thống', reasons: ['Chờ bảo trì', 'Chuyển mã/Setup', 'Mất điện'] }
];

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { Role, Machine, MachineStatus, MachineBrand, DowntimeEvent } from './types';
import OperatorDashboard from './components/OperatorDashboard';
import ManagerDashboard from './components/ManagerDashboard';
import MaintenanceDashboard from './components/MaintenanceDashboard';
import TeamLeaderDashboard from './components/TeamLeaderDashboard';
import Sidebar from './components/Sidebar';

const INITIAL_MACHINES: Machine[] = [
  { id: '1', code: 'CLF-01', brand: MachineBrand.CLF, capacity: 160, status: MachineStatus.RUNNING },
  { id: '2', code: 'CLF-02', brand: MachineBrand.CLF, capacity: 250, status: MachineStatus.RUNNING },
  { id: '3', code: 'JAD-01', brand: MachineBrand.JAD, capacity: 120, status: MachineStatus.STOPPED, currentDowntimeReason: 'Chất lượng SP' },
  { id: '4', code: 'JAD-02', brand: MachineBrand.JAD, capacity: 180, status: MachineStatus.RUNNING },
  { id: '5', code: 'CLF-03', brand: MachineBrand.CLF, capacity: 450, status: MachineStatus.RUNNING },
];

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<Role>(Role.OPERATOR);
  const [machines, setMachines] = useState<Machine[]>(INITIAL_MACHINES);
  const [events, setEvents] = useState<DowntimeEvent[]>([]);

  // Simulation: Add some historical downtime events
  useEffect(() => {
    const historicalEvents: DowntimeEvent[] = [
      { id: 'e1', machineId: '1', startTime: Date.now() - 3600000, endTime: Date.now() - 1800000, reason: 'Kẹt khuôn', category: 'Khuôn' },
      { id: 'e2', machineId: '3', startTime: Date.now() - 7200000, reason: 'Chất lượng SP', category: 'Vận hành' },
    ];
    setEvents(historicalEvents);
  }, []);

  const handleUpdateMachineStatus = (machineId: string, status: MachineStatus, reason?: string) => {
    setMachines(prev => prev.map(m => {
      if (m.id === machineId) {
        return { ...m, status, currentDowntimeReason: reason };
      }
      return m;
    }));

    if (status === MachineStatus.STOPPED && reason) {
      const newEvent: DowntimeEvent = {
        id: Math.random().toString(36).substr(2, 9),
        machineId,
        startTime: Date.now(),
        reason,
        category: 'Chưa phân loại' // Simplified for demo
      };
      setEvents(prev => [...prev, newEvent]);
    } else if (status === MachineStatus.RUNNING) {
      setEvents(prev => prev.map(e => {
        if (e.machineId === machineId && !e.endTime) {
          return { ...e, endTime: Date.now() };
        }
        return e;
      }));
    }
  };

  const renderDashboard = () => {
    switch (userRole) {
      case Role.OPERATOR:
        return <OperatorDashboard machines={machines} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.MANAGER:
        return <ManagerDashboard machines={machines} events={events} />;
      case Role.MAINTENANCE:
        return <MaintenanceDashboard machines={machines} events={events} />;
      case Role.TEAM_LEADER:
        return <TeamLeaderDashboard machines={machines} events={events} onUpdateStatus={handleUpdateMachineStatus} />;
      default:
        return <div className="p-8">Vui lòng chọn vai trò.</div>;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar userRole={userRole} onRoleChange={setUserRole} />
      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="mb-8 flex justify-between items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200">
          <div>
            <h1 className="text-2xl font-bold text-slate-800">SmartMolding Dashboard</h1>
            <p className="text-slate-500 text-sm">Hệ thống theo dõi gián đoạn sản xuất thời gian thực</p>
          </div>
          <div className="flex items-center gap-3">
            <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-xs font-semibold animate-pulse">Live</span>
            <div className="text-right">
              <p className="text-sm font-medium text-slate-700">{new Date().toLocaleDateString('vi-VN')}</p>
              <p className="text-xs text-slate-500">Ca: Hành chính (08:00 - 17:00)</p>
            </div>
          </div>
        </header>

        {renderDashboard()}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { Role } from '../types';

interface SidebarProps {
  userRole: Role;
  onRoleChange: (role: Role) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ userRole, onRoleChange }) => {
  const roles = [
    { id: Role.OPERATOR, label: 'Công Nhân', icon: '👷' },
    { id: Role.TEAM_LEADER, label: 'Tổ Trưởng', icon: '🎖️' },
    { id: Role.MAINTENANCE, label: 'Bảo Trì', icon: '🔧' },
    { id: Role.MANAGER, label: 'Quản Lý', icon: '📊' },
  ];

  return (
    <div className="w-20 md:w-64 bg-slate-900 text-white flex flex-col transition-all">
      <div className="p-6 text-center border-b border-slate-800">
        <div className="hidden md:block text-xl font-black tracking-wider text-blue-400">SMART MOLD</div>
        <div className="md:hidden text-2xl">⚡</div>
      </div>

      <nav className="flex-1 py-6 px-2 space-y-2">
        <p className="hidden md:block px-4 text-xs font-bold text-slate-500 uppercase tracking-widest mb-4">Chế độ xem</p>
        {roles.map((role) => (
          <button
            key={role.id}
            onClick={() => onRoleChange(role.id)}
            className={`w-full flex items-center p-3 rounded-lg transition-all ${
              userRole === role.id 
              ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
              : 'text-slate-400 hover:bg-slate-800 hover:text-white'
            }`}
          >
            <span className="text-xl">{role.icon}</span>
            <span className="ml-3 hidden md:block font-medium">{role.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 bg-slate-800/50 text-xs text-slate-500 hidden md:block">
        <p>Phiên bản 1.0.4-LTS</p>
        <p>© 2024 TechSolutions</p>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { Machine, MachineStatus, DOWNTIME_REASONS } from '../types';

interface OperatorDashboardProps {
  machines: Machine[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const OperatorDashboard: React.FC<OperatorDashboardProps> = ({ machines, onUpdateStatus }) => {
  const [selectedMachine, setSelectedMachine] = useState<Machine | null>(null);
  const [showReasonModal, setShowReasonModal] = useState(false);

  const handleMachineClick = (machine: Machine) => {
    setSelectedMachine(machine);
    if (machine.status === MachineStatus.RUNNING) {
      setShowReasonModal(true);
    } else {
      onUpdateStatus(machine.id, MachineStatus.RUNNING);
    }
  };

  const selectReason = (reason: string) => {
    if (selectedMachine) {
      onUpdateStatus(selectedMachine.id, MachineStatus.STOPPED, reason);
      setShowReasonModal(false);
      setSelectedMachine(null);
    }
  };

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
      {machines.map((machine) => (
        <button
          key={machine.id}
          onClick={() => handleMachineClick(machine)}
          className={`relative p-8 rounded-2xl shadow-lg border-2 transition-all active:scale-95 ${
            machine.status === MachineStatus.RUNNING 
            ? 'bg-white border-green-200 hover:border-green-400' 
            : 'bg-red-50 border-red-200 hover:border-red-400'
          }`}
        >
          <div className="flex justify-between items-start mb-4">
            <span className={`px-3 py-1 rounded-lg text-xs font-bold uppercase tracking-wide ${
              machine.brand === 'CLF' ? 'bg-orange-100 text-orange-700' : 'bg-blue-100 text-blue-700'
            }`}>
              {machine.brand}
            </span>
            <span className={`w-4 h-4 rounded-full ${
              machine.status === MachineStatus.RUNNING ? 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.6)]' : 'bg-red-500 animate-pulse'
            }`}></span>
          </div>

          <h3 className="text-4xl font-black text-slate-800 mb-1">{machine.code}</h3>
          <p className="text-slate-500 font-medium mb-6">Tải trọng: {machine.capacity}T</p>

          <div className="flex flex-col gap-2">
             <div className={`py-4 px-6 rounded-xl font-bold text-xl uppercase ${
                machine.status === MachineStatus.RUNNING ? 'bg-green-500 text-white' : 'bg-red-600 text-white'
             }`}>
               {machine.status === MachineStatus.RUNNING ? 'Máy Đang Chạy' : 'Máy Đang Dừng'}
             </div>
             {machine.status === MachineStatus.STOPPED && machine.currentDowntimeReason && (
               <p className="text-red-700 text-sm font-bold bg-red-100 py-1 rounded">Lý do: {machine.currentDowntimeReason}</p>
             )}
          </div>
          <p className="mt-4 text-xs text-slate-400 italic">Chạm để {machine.status === MachineStatus.RUNNING ? 'BÁO DỪNG' : 'BÁO CHẠY'}</p>
        </button>
      ))}

      {showReasonModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <h2 className="text-2xl font-bold text-slate-800">Chọn Nguyên Nhân Dừng {selectedMachine?.code}</h2>
              <button onClick={() => setShowReasonModal(false)} className="text-slate-400 text-3xl">&times;</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
              {DOWNTIME_REASONS.map((group) => (
                <div key={group.category}>
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-3">{group.category}</h4>
                  <div className="space-y-2">
                    {group.reasons.map(reason => (
                      <button
                        key={reason}
                        onClick={() => selectReason(reason)}
                        className="w-full text-left p-4 rounded-xl border-2 border-slate-100 hover:border-blue-400 hover:bg-blue-50 transition-all font-semibold text-slate-700"
                      >
                        {reason}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 border-t border-slate-100 flex justify-end bg-slate-50">
               <button 
                onClick={() => setShowReasonModal(false)}
                className="px-8 py-3 bg-slate-200 text-slate-700 rounded-xl font-bold hover:bg-slate-300 transition-colors"
               >
                 Hủy Bỏ
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OperatorDashboard;

import React from 'react';
import { Machine, DowntimeEvent, MachineStatus } from '../types';

interface MaintenanceDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
}

const MaintenanceDashboard: React.FC<MaintenanceDashboardProps> = ({ machines, events }) => {
  const maintenancePending = machines.filter(m => m.status === MachineStatus.STOPPED);
  const activeEvents = events.filter(e => !e.endTime);

  return (
    <div className="space-y-8">
      <div className="bg-orange-50 border-l-4 border-orange-400 p-4 rounded-r-xl">
        <h3 className="text-orange-800 font-bold flex items-center gap-2">
          <span>⚠️</span> Cần Xử Lý Ngay ({maintenancePending.length})
        </h3>
        <p className="text-orange-700 text-sm">Các máy đang dừng chờ kỹ thuật kiểm tra.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {maintenancePending.map(machine => {
          const event = activeEvents.find(e => e.machineId === machine.id);
          return (
            <div key={machine.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="text-xl font-bold text-slate-800">{machine.code}</h4>
                  <p className="text-sm text-slate-500">{machine.brand} - {machine.capacity}T</p>
                </div>
                <span className="bg-red-100 text-red-700 px-3 py-1 rounded-full text-xs font-bold uppercase">
                  Down
                </span>
              </div>

              <div className="mb-6 p-4 bg-slate-50 rounded-xl">
                <p className="text-xs font-bold text-slate-400 uppercase mb-1">Lý do báo dừng:</p>
                <p className="text-slate-800 font-semibold">{machine.currentDowntimeReason || 'Không rõ'}</p>
                <p className="text-xs text-slate-500 mt-2 italic">Bắt đầu lúc: {event ? new Date(event.startTime).toLocaleTimeString() : '--:--'}</p>
              </div>

              <div className="space-y-3">
                <textarea 
                  placeholder="Nhập ghi chú sửa chữa..."
                  className="w-full p-3 text-sm border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none"
                  rows={3}
                />
                <button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition-colors shadow-lg shadow-blue-200">
                  Xác Nhận Đã Xử Lý
                </button>
              </div>
            </div>
          );
        })}

        {maintenancePending.length === 0 && (
          <div className="col-span-full py-12 text-center bg-white rounded-3xl border-2 border-dashed border-slate-200">
            <p className="text-slate-400 font-medium">Hiện không có máy nào gặp sự cố kỹ thuật.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaintenanceDashboard;

import React from 'react';
import { Machine, DowntimeEvent, MachineStatus } from '../types';

interface TeamLeaderDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const TeamLeaderDashboard: React.FC<TeamLeaderDashboardProps> = ({ machines, events, onUpdateStatus }) => {
  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h3 className="font-bold text-slate-800">Tình Trạng Máy Trong Ca</h3>
          <button className="text-blue-600 text-sm font-semibold hover:underline">Xuất báo cáo ca</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-xs font-bold uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">Mã Máy</th>
                <th className="px-6 py-4">Trạng Thái</th>
                <th className="px-6 py-4">Lý Do Dừng</th>
                <th className="px-6 py-4">Thời Gian Dừng</th>
                <th className="px-6 py-4">Thao Tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {machines.map(machine => {
                const activeEvent = events.find(e => e.machineId === machine.id && !e.endTime);
                let duration = '0m';
                if (activeEvent) {
                  const diff = Math.floor((Date.now() - activeEvent.startTime) / 60000);
                  duration = `${diff}m`;
                }

                return (
                  <tr key={machine.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="font-bold text-slate-800">{machine.code}</div>
                      <div className="text-xs text-slate-500">{machine.brand}</div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${
                        machine.status === MachineStatus.RUNNING 
                        ? 'bg-green-100 text-green-700' 
                        : 'bg-red-100 text-red-700'
                      }`}>
                        {machine.status === MachineStatus.RUNNING ? 'Đang Chạy' : 'Đang Dừng'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                      {machine.currentDowntimeReason || '-'}
                    </td>
                    <td className="px-6 py-4 text-sm font-mono font-bold text-slate-700">
                      {machine.status === MachineStatus.STOPPED ? duration : '-'}
                    </td>
                    <td className="px-6 py-4">
                      <button className="text-slate-400 hover:text-blue-600 transition-colors">
                        ⚙️ Sửa lý do
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="font-bold text-slate-800 mb-4">Lịch sử gián đoạn gần đây</h3>
          <div className="space-y-4">
            {events.slice(-5).reverse().map(event => (
              <div key={event.id} className="flex items-center gap-4 p-3 hover:bg-slate-50 rounded-xl border border-transparent hover:border-slate-100 transition-all">
                <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-lg">
                  🚨
                </div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-slate-800">
                    {machines.find(m => m.id === event.machineId)?.code} - {event.reason}
                  </p>
                  <p className="text-xs text-slate-500">
                    Bắt đầu: {new Date(event.startTime).toLocaleTimeString()}
                  </p>
                </div>
                <div className="text-right">
                  <span className="text-xs font-bold text-slate-400 uppercase">{event.category}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="bg-blue-600 p-6 rounded-2xl shadow-lg shadow-blue-200 text-white">
          <h3 className="font-bold mb-4">Tóm tắt ca</h3>
          <div className="space-y-6">
            <div>
              <p className="text-blue-200 text-xs font-bold uppercase tracking-wider">Tổng thời gian dừng</p>
              <p className="text-3xl font-black">142 phút</p>
            </div>
            <div>
              <p className="text-blue-200 text-xs font-bold uppercase tracking-wider">Số lần can thiệp</p>
              <p className="text-3xl font-black">8 lần</p>
            </div>
            <button className="w-full py-3 bg-white/10 hover:bg-white/20 rounded-xl font-bold transition-all border border-white/20">
              Giao ca (Handover)
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TeamLeaderDashboard;

import React, { useMemo } from 'react';
import { Machine, DowntimeEvent, MachineBrand } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

interface ManagerDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
}

const ManagerDashboard: React.FC<ManagerDashboardProps> = ({ machines, events }) => {
  const stats = useMemo(() => {
    const totalDowntimeMinutes = events.reduce((acc, e) => {
      const end = e.endTime || Date.now();
      return acc + (end - e.startTime) / 60000;
    }, 0);

    const reasonsCount = events.reduce((acc: Record<string, number>, e) => {
      acc[e.reason] = (acc[e.reason] || 0) + 1;
      return acc;
    }, {});

    const pieData = Object.entries(reasonsCount).map(([name, value]) => ({ name, value }));

    const brandComparison = [
      { 
        name: 'CLF', 
        minutes: events
          .filter(e => machines.find(m => m.id === e.machineId)?.brand === MachineBrand.CLF)
          .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0)
      },
      { 
        name: 'JAD', 
        minutes: events
          .filter(e => machines.find(m => m.id === e.machineId)?.brand === MachineBrand.JAD)
          .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0)
      },
    ];

    return { totalDowntimeMinutes, pieData, brandComparison };
  }, [events, machines]);

  const COLORS = ['#3b82f6', '#ef4444', '#f59e0b', '#10b981', '#6366f1', '#ec4899'];

  return (
    <div className="space-y-8 pb-12">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Availability (OEE)</p>
          <p className="text-4xl font-black text-blue-600">88.4%</p>
          <p className="text-xs text-green-500 mt-2">↑ 2.1% so với hôm qua</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Tổng Thời Gian Dừng</p>
          <p className="text-4xl font-black text-slate-800">{Math.round(stats.totalDowntimeMinutes)} m</p>
          <p className="text-xs text-slate-500 mt-2">Tính từ đầu ca</p>
