import React, { useMemo, useState } from 'react';
import { Machine, DowntimeEvent, MachineBrand } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

interface ManagerDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateMachine: (machineId: string, updates: Partial<Machine>) => void;
}

const ManagerDashboard: React.FC<ManagerDashboardProps> = ({ machines, events, onUpdateMachine }) => {
  const [editingMachine, setEditingMachine] = useState<Machine | null>(null);
  const [newCode, setNewCode] = useState('');

  const stats = useMemo(() => {
    const totalDowntimeMinutes = events.reduce((acc, e) => {
      const end = e.endTime || Date.now();
      return acc + (end - e.startTime) / 60000;
    }, 0);

    const reasonsCount = events.reduce((acc: Record<string, number>, e) => {
      acc[e.reason] = (acc[e.reason] || 0) + 1;
      return acc;
    }, {});

    const pieData = Object.entries(reasonsCount).map(([name, value]) => ({ name, value }));

    const brandComparison = [
      { 
        name: 'CLF', 
        minutes: events
          .filter(e => machines.find(m => m.id === e.machineId)?.brand === MachineBrand.CLF)
          .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0)
      },
      { 
        name: 'JAD', 
        minutes: events
          .filter(e => machines.find(m => m.id === e.machineId)?.brand === MachineBrand.JAD)
          .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0)
      },
    ];

    return { totalDowntimeMinutes, pieData, brandComparison };
  }, [events, machines]);

  const COLORS = ['#3b82f6', '#ef4444', '#f59e0b', '#10b981', '#6366f1', '#ec4899'];

  const handleEditClick = (machine: Machine) => {
    setEditingMachine(machine);
    setNewCode(machine.code);
  };

  const handleSaveName = () => {
    if (editingMachine && newCode.trim()) {
      onUpdateMachine(editingMachine.id, { code: newCode.trim() });
      setEditingMachine(null);
    }
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Các khối thống kê trên cùng */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Availability (OEE)</p>
          <p className="text-4xl font-black text-blue-600">88.4%</p>
          <p className="text-xs text-green-500 mt-2">↑ 2.1% so với hôm qua</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Tổng Thời Gian Dừng</p>
          <p className="text-4xl font-black text-slate-800">{Math.round(stats.totalDowntimeMinutes)} m</p>
          <p className="text-xs text-slate-500 mt-2">Tính từ đầu ca</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Số Lần Gián Đoạn</p>
          <p className="text-4xl font-black text-slate-800">{events.length}</p>
          <p className="text-xs text-red-500 mt-2">Dữ liệu thời gian thực</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Máy Đang Chạy</p>
          <p className="text-4xl font-black text-green-600">{machines.filter(m => m.status === 'RUNNING').length}/{machines.length}</p>
          <p className="text-xs text-slate-500 mt-2">91% công suất hoạt động</p>
        </div>
      </div>

      {/* Biểu đồ */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Phân Tích Nguyên Nhân Dừng Máy</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Thời Gian Dừng CLF vs JAD (Phút)</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.brandComparison}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="minutes" fill="#3b82f6" radius={[8, 8, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Bảng chi tiết máy - Cho phép sửa tên */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/30">
          <h3 className="font-bold text-slate-800">Hiệu suất chi tiết từng máy</h3>
          <button className="px-4 py-2 bg-white border border-slate-200 hover:bg-slate-50 rounded-lg text-sm font-bold text-slate-700 transition-all">
            Xuất Excel (.xlsx)
          </button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr>
                <th className="px-8 py-4">Mã Máy</th>
                <th className="px-8 py-4">Loại</th>
                <th className="px-8 py-4">Số Lần Dừng</th>
                <th className="px-8 py-4">Tổng Thời Gian</th>
                <th className="px-8 py-4">Dự Kiến OEE</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {machines.map(m => {
                const machineEvents = events.filter(e => e.machineId === m.id);
                const totalMins = machineEvents.reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0);
                return (
                  <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-8 py-5">
                       <div className="flex items-center gap-2">
                          <span className="font-bold text-slate-800">{m.code}</span>
                          <button 
                            onClick={() => handleEditClick(m)}
                            className="text-xs text-blue-400 hover:text-blue-600"
                            title="Đổi tên máy"
                          >
                            ✏️
                          </button>
                       </div>
                    </td>
                    <td className="px-8 py-5 text-sm text-slate-500 font-bold uppercase">{m.brand}</td>
                    <td className="px-8 py-5 text-sm font-semibold">{machineEvents.length}</td>
                    <td className="px-8 py-5 text-sm font-mono">{Math.round(totalMins)} phút</td>
                    <td className="px-8 py-5">
                      <div className="w-24 bg-slate-100 h-2 rounded-full overflow-hidden">
                        <div className="bg-blue-500 h-full" style={{ width: `${Math.max(30, 100 - totalMins / 5)}%` }}></div>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal chỉnh sửa nhanh tên máy (Manager) */}
      {editingMachine && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
           <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-xl">
              <h3 className="font-bold text-slate-800 mb-4">Đổi mã máy</h3>
              <input 
                type="text"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500 mb-4 font-bold"
                value={newCode}
                onChange={(e) => setNewCode(e.target.value)}
                autoFocus
              />
              <div className="flex gap-2">
                <button 
                  onClick={() => setEditingMachine(null)}
                  className="flex-1 py-2 bg-slate-100 text-slate-600 rounded-lg font-bold"
                >
                  Hủy
                </button>
                <button 
                  onClick={handleSaveName}
                  className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-bold"
                >
                  Lưu
                </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

