import React, { useMemo, useState } from 'react';
import { Machine, DowntimeEvent, MachineBrand, MachineType } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';

interface ManagerDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateMachine: (machineId: string, updates: Partial<Machine>) => void;
}

const ManagerDashboard: React.FC<ManagerDashboardProps> = ({ machines, events, onUpdateMachine }) => {
  const [editingMachine, setEditingMachine] = useState<Machine | null>(null);
  const [newCode, setNewCode] = useState('');
  const [newBrand, setNewBrand] = useState<MachineBrand>(MachineBrand.CLF);

  const stats = useMemo(() => {
    const totalDowntimeMinutes = events.reduce((acc, e) => {
      const end = e.endTime || Date.now();
      return acc + (end - e.startTime) / 60000;
    }, 0);

    const reasonsCount = events.reduce((acc: Record<string, number>, e) => {
      acc[e.reason] = (acc[e.reason] || 0) + 1;
      return acc;
    }, {});

    const pieData = Object.entries(reasonsCount).map(([name, value]) => ({ name, value }));

    // Thống kê động theo tất cả các thương hiệu hiện có
    const brandsInUse = Array.from(new Set(machines.map(m => m.brand)));
    const brandComparison = brandsInUse.map(brand => ({
      name: brand,
      minutes: events
        .filter(e => machines.find(m => m.id === e.machineId)?.brand === brand)
        .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0)
    }));

    return { totalDowntimeMinutes, pieData, brandComparison };
  }, [events, machines]);

  const COLORS = ['#3b82f6', '#ef4444', '#f59e0b', '#10b981', '#6366f1', '#ec4899'];

  const handleEditClick = (machine: Machine) => {
    setEditingMachine(machine);
    setNewCode(machine.code);
    setNewBrand(machine.brand);
  };

  const handleSave = () => {
    if (editingMachine && newCode.trim()) {
      onUpdateMachine(editingMachine.id, { 
        code: newCode.trim(),
        brand: newBrand
      });
      setEditingMachine(null);
    }
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Khối thống kê - Giữ nguyên */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Availability</p>
          <p className="text-4xl font-black text-blue-600">88.4%</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Downtime (Phút)</p>
          <p className="text-4xl font-black text-slate-800">{Math.round(stats.totalDowntimeMinutes)}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Sự Cố</p>
          <p className="text-4xl font-black text-red-600">{events.length}</p>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <p className="text-slate-500 text-xs font-bold uppercase tracking-wider mb-2">Online</p>
          <p className="text-4xl font-black text-green-600">{machines.filter(m => m.status === 'RUNNING').length}</p>
        </div>
      </div>

      {/* Biểu đồ */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Phân Tích Lý Do</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="value">
                  {stats.pieData.map((entry, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Downtime theo Thương Hiệu</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.brandComparison}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="minutes" fill="#3b82f6" radius={[8, 8, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Bảng chi tiết */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/30">
          <h3 className="font-bold text-slate-800">Danh sách thiết bị toàn xưởng</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
              <tr>
                <th className="px-8 py-4">Mã Máy</th>
                <th className="px-8 py-4">Thương Hiệu</th>
                <th className="px-8 py-4">Loại Máy</th>
                <th className="px-8 py-4">Thời Gian Dừng</th>
                <th className="px-8 py-4">Hành động</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {machines.map(m => {
                const totalMins = events
                  .filter(e => e.machineId === m.id)
                  .reduce((acc, e) => acc + ((e.endTime || Date.now()) - e.startTime) / 60000, 0);
                return (
                  <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-8 py-5 font-bold text-slate-800">{m.code}</td>
                    <td className="px-8 py-5 text-sm font-bold text-blue-600 uppercase">{m.brand}</td>
                    <td className="px-8 py-5 text-sm text-slate-500 font-medium">
                      {m.type === MachineType.INJECTION ? 'Máy Ép' : 'Máy Thổi'}
