import React, { useState, useEffect } from 'react';
import { Role, Machine, MachineStatus, MachineBrand, MachineType, DowntimeEvent } from './types';
import OperatorDashboard from './components/OperatorDashboard';
import ManagerDashboard from './components/ManagerDashboard';
import MaintenanceDashboard from './components/MaintenanceDashboard';
import TeamLeaderDashboard from './components/TeamLeaderDashboard';
import Sidebar from './components/Sidebar';

// Tạo dữ liệu mẫu cho 84 máy
const generateMachines = (): Machine[] => {
  const machines: Machine[] = [];
  // 75 Máy ép (Injection)
  for (let i = 1; i <= 75; i++) {
    const brand = i % 2 === 0 ? MachineBrand.CLF : MachineBrand.JAD;
    machines.push({
      id: `inj-${i}`,
      code: `IM-${i.toString().padStart(2, '0')}`,
      brand: brand,
      type: MachineType.INJECTION,
      capacity: i % 3 === 0 ? 160 : (i % 2 === 0 ? 250 : 120),
      status: Math.random() > 0.15 ? MachineStatus.RUNNING : MachineStatus.STOPPED,
      currentDowntimeReason: Math.random() > 0.85 ? 'Chờ QC' : undefined
    });
  }
  // 9 Máy thổi (Blowing)
  for (let i = 1; i <= 9; i++) {
    machines.push({
      id: `blo-${i}`,
      code: `BM-${i.toString().padStart(2, '0')}`,
      brand: MachineBrand.OTHER,
      type: MachineType.BLOWING,
      capacity: 50,
      status: Math.random() > 0.1 ? MachineStatus.RUNNING : MachineStatus.STOPPED,
      currentDowntimeReason: Math.random() > 0.9 ? 'Thiếu liệu' : undefined
    });
  }
  return machines;
};

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<Role>(Role.OPERATOR);
  const [machines, setMachines] = useState<Machine[]>(generateMachines());
  const [events, setEvents] = useState<DowntimeEvent[]>([]);

  useEffect(() => {
    const initialEvents = machines
      .filter(m => m.status === MachineStatus.STOPPED)
      .map(m => ({
        id: `init-e-${m.id}`,
        machineId: m.id,
        startTime: Date.now() - Math.random() * 3600000,
        reason: m.currentDowntimeReason || 'Lỗi hệ thống',
        category: 'Vận hành'
      }));
    setEvents(initialEvents);
  }, []);

  const handleUpdateMachineStatus = (machineId: string, status: MachineStatus, reason?: string) => {
    setMachines(prev => prev.map(m => {
      if (m.id === machineId) {
        return { ...m, status, currentDowntimeReason: reason };
      }
      return m;
    }));

    if (status === MachineStatus.STOPPED && reason) {
      const newEvent: DowntimeEvent = {
        id: Math.random().toString(36).substr(2, 9),
        machineId,
        startTime: Date.now(),
        reason,
        category: 'Chưa phân loại'
      };
      setEvents(prev => [...prev, newEvent]);
    } else if (status === MachineStatus.RUNNING) {
      setEvents(prev => prev.map(e => {
        if (e.machineId === machineId && !e.endTime) {
          return { ...e, endTime: Date.now() };
        }
        return e;
      }));
    }
  };

  const handleUpdateMachineDetails = (machineId: string, updates: Partial<Machine>) => {
    setMachines(prev => prev.map(m => m.id === machineId ? { ...m, ...updates } : m));
  };

  const renderDashboard = () => {
    switch (userRole) {
      case Role.OPERATOR:
        return <OperatorDashboard machines={machines} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.MANAGER:
        return <ManagerDashboard machines={machines} events={events} onUpdateMachine={handleUpdateMachineDetails} />;
      case Role.MAINTENANCE:
        return <MaintenanceDashboard machines={machines} events={events} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.TEAM_LEADER:
        return <TeamLeaderDashboard machines={machines} events={events} onUpdateStatus={handleUpdateMachineStatus} onUpdateMachine={handleUpdateMachineDetails} />;
      default:
        return <div className="p-8">Vui lòng chọn vai trò.</div>;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900">
      <Sidebar userRole={userRole} onRoleChange={setUserRole} />
      <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8">
        <header className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
          <div>
            <h1 className="text-2xl font-black text-slate-800">SmartMolding Pro</h1>
            <p className="text-slate-500 text-sm font-medium">Quản lý 84 máy (75 Ép | 9 Thổi)</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="bg-slate-100 px-4 py-2 rounded-xl text-center">
              <p className="text-[10px] font-bold text-slate-500 uppercase">Đang Chạy</p>
              <p className="text-xl font-black text-green-600">{machines.filter(m => m.status === MachineStatus.RUNNING).length}</p>
            </div>
            <div className="bg-slate-100 px-4 py-2 rounded-xl text-center">
              <p className="text-[10px] font-bold text-slate-500 uppercase">Đang Dừng</p>
              <p className="text-xl font-black text-red-600">{machines.filter(m => m.status === MachineStatus.STOPPED).length}</p>
            </div>
          </div>
        </header>

        {renderDashboard()}
      </main>
    </div>
  );
};

