import React, { useState, useMemo } from 'react';
import { Machine, MachineStatus, MachineType, DOWNTIME_REASONS } from '../types';

interface OperatorDashboardProps {
  machines: Machine[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const OperatorDashboard: React.FC<OperatorDashboardProps> = ({ machines, onUpdateStatus }) => {
  const [filterType, setFilterType] = useState<MachineType | 'ALL'>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedMachine, setSelectedMachine] = useState<Machine | null>(null);
  const [showReasonModal, setShowReasonModal] = useState(false);

  const filteredMachines = useMemo(() => {
    return machines.filter(m => {
      const matchesType = filterType === 'ALL' || m.type === filterType;
      const matchesSearch = m.code.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [machines, filterType, searchQuery]);

  const handleMachineClick = (machine: Machine) => {
    setSelectedMachine(machine);
    if (machine.status === MachineStatus.RUNNING) {
      setShowReasonModal(true);
    } else {
      onUpdateStatus(machine.id, MachineStatus.RUNNING);
    }
  };

  const selectReason = (reason: string) => {
    if (selectedMachine) {
      onUpdateStatus(selectedMachine.id, MachineStatus.STOPPED, reason);
      setShowReasonModal(false);
      setSelectedMachine(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex bg-slate-100 p-1 rounded-lg">
          <button 
            onClick={() => setFilterType('ALL')}
            className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === 'ALL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
          >
            Tất cả
          </button>
          <button 
            onClick={() => setFilterType(MachineType.INJECTION)}
            className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === MachineType.INJECTION ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
          >
            Máy Ép
          </button>
          <button 
            onClick={() => setFilterType(MachineType.BLOWING)}
            className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === MachineType.BLOWING ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
          >
            Máy Thổi
          </button>
        </div>
        <div className="flex-1 w-full relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">🔍</span>
          <input 
            type="text" 
            placeholder="Tìm mã máy..."
            className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 xl:grid-cols-8 gap-3">
        {filteredMachines.map((machine) => {
          const isPlanned = machine.currentDowntimeReason === 'Không đơn hàng';
          return (
            <button
              key={machine.id}
              onClick={() => handleMachineClick(machine)}
              className={`flex flex-col items-center justify-center p-4 rounded-xl border-2 transition-all active:scale-95 shadow-sm ${
                machine.status === MachineStatus.RUNNING 
                ? 'bg-white border-slate-100 hover:border-green-400' 
                : isPlanned 
                  ? 'bg-blue-50 border-blue-200 hover:border-blue-500 shadow-blue-100'
                  : 'bg-red-50 border-red-200 hover:border-red-500 shadow-red-100'
              }`}
            >
              <div className="flex items-center gap-1 mb-1">
                 <div className={`w-2 h-2 rounded-full ${
                   machine.status === MachineStatus.RUNNING 
                   ? 'bg-green-500 shadow-[0_0_5px_rgba(34,197,94,0.5)]' 
                   : isPlanned ? 'bg-blue-500' : 'bg-red-500 animate-pulse'
                 }`}></div>
                 <span className="text-[10px] font-bold text-slate-400 uppercase">{machine.type === MachineType.INJECTION ? 'Ép' : 'Thổi'}</span>
              </div>
              <h3 className={`text-xl font-black ${
                machine.status === MachineStatus.RUNNING 
                ? 'text-slate-800' 
                : isPlanned ? 'text-blue-700' : 'text-red-700'
              }`}>
                {machine.code}
              </h3>
              <p className="text-[10px] text-slate-400 font-bold">{machine.brand}</p>
              {machine.status === MachineStatus.STOPPED && (
                <div className={`mt-2 w-full truncate text-[9px] font-bold py-1 px-1 rounded text-center ${
                  isPlanned ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'
                }`}>
                  {machine.currentDowntimeReason || 'Dừng'}
                </div>
              )}
            </button>
          );
        })}
      </div>

      {showReasonModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-bold text-slate-800 tracking-tight">Báo Dừng Máy {selectedMachine?.code}</h2>
                <p className="text-slate-500 text-sm">Chọn lý do dừng chính xác (OEE sẽ loại trừ 'Không đơn hàng')</p>
              </div>
              <button onClick={() => setShowReasonModal(false)} className="text-slate-400 text-3xl hover:text-slate-600">&times;</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
              {DOWNTIME_REASONS.map((group) => (
                <div key={group.category}>
                  <h4 className={`text-xs font-black uppercase tracking-widest mb-3 border-b border-slate-100 pb-1 ${group.category === 'Kế hoạch' ? 'text-blue-500' : 'text-slate-400'}`}>
                    {group.category}
                  </h4>
                  <div className="space-y-2">
                    {group.reasons.map(reason => (
                      <button
                        key={reason}
                        onClick={() => selectReason(reason)}
                        className={`w-full text-left p-3 rounded-xl border transition-all font-bold text-sm active:bg-blue-100 ${
                          reason === 'Không đơn hàng' 
                          ? 'border-blue-200 bg-blue-50/50 hover:border-blue-500 text-blue-700' 
                          : 'border-slate-200 hover:border-blue-500 hover:bg-blue-50 text-slate-700'
                        }`}
                      >
                        {reason}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="p-6 border-t border-slate-100 flex justify-end bg-slate-50 gap-3">
               <button onClick={() => setShowReasonModal(false)} className="px-6 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold">Đóng</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OperatorDashboard;

import React, { useState } from 'react';
import { Machine, DowntimeEvent, MachineStatus } from '../types';

interface MaintenanceDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const MaintenanceDashboard: React.FC<MaintenanceDashboardProps> = ({ machines, events, onUpdateStatus }) => {
  const [notes, setNotes] = useState<Record<string, string>>({});

  // Lấy các sự kiện đang diễn ra (chưa kết thúc)
  const activeEvents = events.filter(e => !e.endTime);

  // Lọc danh sách máy chờ bảo trì: 
  // 1. Máy đang ở trạng thái STOPPED
  // 2. Sự kiện gây dừng máy KHÔNG phải là loại có kế hoạch (isPlanned = false)
  const maintenancePending = machines.filter(m => {
    if (m.status !== MachineStatus.STOPPED) return false;
    const event = activeEvents.find(e => e.machineId === m.id);
    // Nếu là sự cố có kế hoạch (như không đơn hàng), bảo trì không cần xử lý
    return event && !event.isPlanned;
  });

  const handleResolve = (machineId: string) => {
    // Chuyển trạng thái máy về RUNNING (Sẽ hiển thị màu xanh ở màn hình Operator)
    onUpdateStatus(machineId, MachineStatus.RUNNING);

    // Clear ghi chú sau khi xong
    setNotes(prev => {
      const newNotes = { ...prev };
      delete newNotes[machineId];
      return newNotes;
    });
  };

  return (
    <div className="space-y-8">
      <div className="bg-blue-50 border-l-4 border-blue-400 p-4 rounded-r-xl flex justify-between items-center">
        <div>
          <h3 className="text-blue-800 font-bold flex items-center gap-2 text-lg">
            <span>🔧</span> Danh Sách Sửa Chữa ({maintenancePending.length})
          </h3>
          <p className="text-blue-700 text-sm">Chỉ hiển thị các máy gặp sự cố kỹ thuật cần can thiệp.</p>
        </div>
        <div className="hidden md:block text-right">
          <span className="text-[10px] font-black text-blue-400 uppercase tracking-widest block">Lưu ý</span>
          <span className="text-xs font-bold text-blue-600">Máy dừng do "Không đơn hàng" sẽ không hiện ở đây.</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {maintenancePending.map(machine => {
          const event = activeEvents.find(e => e.machineId === machine.id);
          const currentNotes = notes[machine.id] || '';

          return (
            <div key={machine.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col animate-in fade-in slide-in-from-bottom-4">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="text-2xl font-black text-slate-800">{machine.code}</h4>
                  <p className="text-xs text-slate-400 font-bold uppercase">{machine.brand} | {machine.capacity}T</p>
                </div>
                <div className="flex flex-col items-end">
                  <span className="bg-red-500 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-sm">
                    Sự Cố Kỹ Thuật
                  </span>
                </div>
              </div>

              <div className="mb-6 p-4 bg-slate-50 rounded-2xl border border-slate-100 flex-1">
                <div className="flex justify-between items-center mb-2">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Lý do báo dừng</p>
                  <p className="text-[10px] font-mono font-bold text-red-400">
                    {event ? new Date(event.startTime).toLocaleTimeString() : '--:--'}
                  </p>
                </div>
                <p className="text-slate-800 font-black text-lg leading-tight">
                  {machine.currentDowntimeReason || 'Yêu cầu kiểm tra'}
                </p>
                <div className="mt-4 pt-4 border-t border-slate-200/50">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Ghi chú sửa chữa</p>
                   <textarea 
                    value={currentNotes}
                    onChange={(e) => setNotes({...notes, [machine.id]: e.target.value})}
                    placeholder="Nhập nội dung đã xử lý (vd: Thay cảm biến, vệ sinh khuôn...)"
                    className="w-full p-3 text-sm border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white min-h-[80px]"
                   />
                </div>
              </div>

              <button 
                onClick={() => handleResolve(machine.id)}
                className="w-full bg-slate-900 hover:bg-green-600 text-white font-black py-4 rounded-2xl transition-all shadow-lg hover:shadow-green-200 flex items-center justify-center gap-2 group"
              >
                <span className="text-lg group-hover:scale-125 transition-transform">✅</span>
                XÁC NHẬN SỬA XONG
              </button>
            </div>
          );
        })}

        {maintenancePending.length === 0 && (
          <div className="col-span-full py-20 text-center bg-white rounded-3xl border-2 border-dashed border-slate-200">
            <div className="text-5xl mb-4">✨</div>
            <p className="text-slate-500 font-bold text-lg">Hệ thống kỹ thuật ổn định.</p>
            <p className="text-slate-400 text-sm">Không có máy nào đang đợi sửa chữa.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaintenanceDashboard;

import React, { useState, useEffect } from 'react';
import { Role, Machine, MachineStatus, MachineBrand, MachineType, DowntimeEvent } from './types';
import OperatorDashboard from './components/OperatorDashboard';
import ManagerDashboard from './components/ManagerDashboard';
import MaintenanceDashboard from './components/MaintenanceDashboard';
import TeamLeaderDashboard from './components/TeamLeaderDashboard';
import Sidebar from './components/Sidebar';

const generateRealMachines = (): Machine[] => {
  const machineData = [
    // CLF Series
    { code: 'CLF125-25', brand: MachineBrand.CLF, capacity: 125 },
    { code: 'CLF180-30', brand: MachineBrand.CLF, capacity: 180 },
    { code: 'CLF180-31', brand: MachineBrand.CLF, capacity: 180 },
    { code: 'CLF180-36', brand: MachineBrand.CLF, capacity: 180 },
    { code: 'CLF180-37', brand: MachineBrand.CLF, capacity: 180 },
    { code: 'CLF250-13', brand: MachineBrand.CLF, capacity: 250 },
    { code: 'CLF400-10', brand: MachineBrand.CLF, capacity: 400 },
    // FKI
    { code: 'FKI', brand: MachineBrand.OTHER, capacity: 100 },
    // KAIMEI (Thổi)
    { code: 'KAIMEI-15', brand: MachineBrand.OTHER, capacity: 15, type: MachineType.BLOWING },
    { code: 'KAIMEI-09', brand: MachineBrand.OTHER, capacity: 9, type: MachineType.BLOWING },
    { code: 'KAIMEI-34', brand: MachineBrand.OTHER, capacity: 34, type: MachineType.BLOWING },
    // SMC (Thổi)
    { code: 'SMC-26', brand: MachineBrand.OTHER, capacity: 26, type: MachineType.BLOWING },
    { code: 'SMC-27', brand: MachineBrand.OTHER, capacity: 27, type: MachineType.BLOWING },
    { code: 'SMC-30', brand: MachineBrand.OTHER, capacity: 30, type: MachineType.BLOWING },
    // CLF 500 Series
    { code: 'CLF500-18', brand: MachineBrand.CLF, capacity: 500 },
    { code: 'CLF500-19', brand: MachineBrand.CLF, capacity: 500 },
    { code: 'CLF500-22', brand: MachineBrand.CLF, capacity: 500 },
    { code: 'CLF500-24', brand: MachineBrand.CLF, capacity: 500 },
    { code: 'CLF500-25', brand: MachineBrand.CLF, capacity: 500 },
    { code: 'CLF500-26', brand: MachineBrand.CLF, capacity: 500 },
    // JAD Series
    { code: 'JAD110-03', brand: MachineBrand.JAD, capacity: 110 },
    { code: 'JAD180-02', brand: MachineBrand.JAD, capacity: 180 },
    { code: 'JAD180-22', brand: MachineBrand.JAD, capacity: 180 },
    { code: 'JAD450-01', brand: MachineBrand.JAD, capacity: 450 },
    { code: 'JAD450-02', brand: MachineBrand.JAD, capacity: 450 },
    { code: 'JAD450-03', brand: MachineBrand.JAD, capacity: 450 },
    { code: 'JAD450-04', brand: MachineBrand.JAD, capacity: 450 },
    { code: 'JAD650-01', brand: MachineBrand.JAD, capacity: 650 },
    { code: 'JAD650-02', brand: MachineBrand.JAD, capacity: 650 },
  ];

  // Map data to full Machine objects and fill up to 84 if needed (đang có 29 máy thực tế từ hình)
  // Trong thực tế sẽ điền đủ 84 máy, ở đây tôi tạo 29 máy này trước
  return machineData.map((m, index) => ({
    id: `m1-${index}`,
    code: m.code,
    brand: m.brand,
    type: m.type || MachineType.INJECTION,
    capacity: m.capacity,
    status: MachineStatus.RUNNING,
  }));
};

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<Role>(Role.OPERATOR);
  const [machines, setMachines] = useState<Machine[]>(generateRealMachines());
  const [events, setEvents] = useState<DowntimeEvent[]>([]);

  const handleUpdateMachineStatus = (machineId: string, status: MachineStatus, reason?: string) => {
    setMachines(prev => prev.map(m => {
      if (m.id === machineId) {
        return { ...m, status, currentDowntimeReason: reason };
      }
      return m;
    }));

    if (status === MachineStatus.STOPPED && reason) {
      const newEvent: DowntimeEvent = {
        id: Math.random().toString(36).substr(2, 9),
        machineId,
        startTime: Date.now(),
        reason,
        category: 'Chưa phân loại',
        isPlanned: reason === 'Không đơn hàng'
      };
      setEvents(prev => [...prev, newEvent]);
    } else if (status === MachineStatus.RUNNING) {
      setEvents(prev => prev.map(e => {
        if (e.machineId === machineId && !e.endTime) {
          return { ...e, endTime: Date.now() };
        }
        return e;
      }));
    }
  };

  const handleUpdateMachineDetails = (machineId: string, updates: Partial<Machine>) => {
    setMachines(prev => prev.map(m => m.id === machineId ? { ...m, ...updates } : m));
  };

  const renderDashboard = () => {
    switch (userRole) {
      case Role.OPERATOR:
        return <OperatorDashboard machines={machines} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.MANAGER:
        return <ManagerDashboard machines={machines} events={events} onUpdateMachine={handleUpdateMachineDetails} />;
      case Role.MAINTENANCE:
        return <MaintenanceDashboard machines={machines} events={events} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.TEAM_LEADER:
        return <TeamLeaderDashboard machines={machines} events={events} onUpdateStatus={handleUpdateMachineStatus} onUpdateMachine={handleUpdateMachineDetails} />;
      default:
        return <div className="p-8">Vui lòng chọn vai trò.</div>;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900">
      <Sidebar userRole={userRole} onRoleChange={setUserRole} />
      <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8">
        <header className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
          <div>
            <h1 className="text-2xl font-black text-slate-800">SmartMolding - Khu Vực 1</h1>
            <p className="text-slate-500 text-sm font-medium">Hệ thống giám sát máy ép & máy thổi</p>
          </div>
          <div className="flex items-center gap-4">
            <div className="bg-slate-100 px-4 py-2 rounded-xl text-center border border-slate-200">
              <p className="text-[10px] font-bold text-slate-500 uppercase">Đang Chạy</p>
              <p className="text-xl font-black text-green-600">{machines.filter(m => m.status === MachineStatus.RUNNING).length}</p>
            </div>
            <div className="bg-slate-100 px-4 py-2 rounded-xl text-center border border-slate-200">
              <p className="text-[10px] font-bold text-slate-500 uppercase">Dừng Sự Cố</p>
