          </div>

          <div className="flex items-center gap-4">
            <div className="bg-green-50 px-4 py-2 rounded-xl text-center border border-green-100 min-w-[80px]">
              <p className="text-[10px] font-bold text-green-600 uppercase">Chạy</p>
