      ...m,
      id: `a2-${i}`,
      area: 2,
      type: MachineType.INJECTION,
      status: MachineStatus.RUNNING
    })),
    ...area3Data.map((m, i) => ({
      ...m,
      id: `a3-${i}`,
      area: 3,
      type: m.type || MachineType.INJECTION,
      status: MachineStatus.RUNNING
    }))
  ];

  return machines;
};

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<Role>(Role.OPERATOR);
  const [selectedArea, setSelectedArea] = useState<1 | 2 | 3 | 'ALL'>(1);
  const [machines, setMachines] = useState<Machine[]>(generateAllMachines());
  const [events, setEvents] = useState<DowntimeEvent[]>([]);

  const filteredMachines = useMemo(() => {
    if (selectedArea === 'ALL') return machines;
    return machines.filter(m => m.area === selectedArea);
  }, [machines, selectedArea]);

  const factoryStats = useMemo(() => {
    const running = machines.filter(m => m.status === MachineStatus.RUNNING).length;
    const stopped = machines.filter(m => m.status === MachineStatus.STOPPED && m.currentDowntimeReason !== 'Không đơn hàng').length;
    const noOrder = machines.filter(m => m.status === MachineStatus.STOPPED && m.currentDowntimeReason === 'Không đơn hàng').length;
    return { total: machines.length, running, stopped, noOrder };
  }, [machines]);

  const handleUpdateMachineStatus = (machineId: string, status: MachineStatus, reason?: string) => {
    setMachines(prev => prev.map(m => {
      if (m.id === machineId) {
        return { ...m, status, currentDowntimeReason: reason };
      }
      return m;
    }));

    if (status === MachineStatus.STOPPED && reason) {
      const newEvent: DowntimeEvent = {
        id: Math.random().toString(36).substr(2, 9),
        machineId,
        startTime: Date.now(),
        reason,
        category: 'Chưa phân loại',
        isPlanned: reason === 'Không đơn hàng'
      };
      setEvents(prev => [...prev, newEvent]);
    } else if (status === MachineStatus.RUNNING) {
      setEvents(prev => prev.map(e => {
        if (e.machineId === machineId && !e.endTime) {
          return { ...e, endTime: Date.now() };
        }
        return e;
      }));
    }
  };

  const handleUpdateMachineDetails = (machineId: string, updates: Partial<Machine>) => {
    setMachines(prev => prev.map(m => m.id === machineId ? { ...m, ...updates } : m));
  };

  const renderDashboard = () => {
    switch (userRole) {
      case Role.OPERATOR:
        return <OperatorDashboard machines={filteredMachines} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.MANAGER:
        return <ManagerDashboard machines={filteredMachines} events={events} onUpdateMachine={handleUpdateMachineDetails} />;
      case Role.MAINTENANCE:
        return <MaintenanceDashboard machines={filteredMachines} events={events} onUpdateStatus={handleUpdateMachineStatus} />;
      case Role.TEAM_LEADER:
        return <TeamLeaderDashboard machines={filteredMachines} events={events} onUpdateStatus={handleUpdateMachineStatus} onUpdateMachine={handleUpdateMachineDetails} />;
      default:
        return <div className="p-8">Vui lòng chọn vai trò.</div>;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900">
      <Sidebar userRole={userRole} onRoleChange={setUserRole} />
      <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8">
        <header className="mb-6 flex flex-col xl:flex-row xl:items-center justify-between gap-4 bg-white p-5 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex flex-col md:flex-row md:items-center gap-4 flex-wrap">
            <div>
              <h1 className="text-2xl font-black text-slate-800 tracking-tight">
                SmartMolding - <span className="text-blue-600">
                  {selectedArea === 'ALL' ? 'Toàn Nhà Máy' : `Khu Vực ${selectedArea}`}
                </span>
              </h1>
              <p className="text-slate-500 text-sm font-medium">Hệ thống giám sát sản xuất đa khu vực</p>
            </div>

            <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
              <button 
                onClick={() => setSelectedArea(1)}
                className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedArea === 1 ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >
                KHU 1
              </button>
              <button 
                onClick={() => setSelectedArea(2)}
                className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedArea === 2 ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >
                KHU 2
              </button>
              <button 
                onClick={() => setSelectedArea(3)}
                className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedArea === 3 ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >
                KHU 3
              </button>
              <button 
                onClick={() => setSelectedArea('ALL')}
                className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedArea === 'ALL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
              >
                TẤT CẢ
              </button>
            </div>
          </div>

          <div className="flex items-center gap-3 overflow-x-auto pb-2 xl:pb-0">
            <div className="bg-slate-50 px-4 py-2 rounded-xl text-center border border-slate-100 min-w-[100px]">
              <p className="text-[10px] font-bold text-slate-400 uppercase">Tổng Máy</p>
              <p className="text-xl font-black text-slate-700">{factoryStats.total}</p>
            </div>
            <div className="bg-green-50 px-4 py-2 rounded-xl text-center border border-green-100 min-w-[100px]">
              <p className="text-[10px] font-bold text-green-600 uppercase">Tổng Chạy</p>
              <p className="text-xl font-black text-green-700">{factoryStats.running}</p>
            </div>
            <div className="bg-red-50 px-4 py-2 rounded-xl text-center border border-red-100 min-w-[100px]">
              <p className="text-[10px] font-bold text-red-600 uppercase">Tổng Lỗi</p>
              <p className="text-xl font-black text-red-700">{factoryStats.stopped}</p>
            </div>
            <div className="bg-blue-50 px-4 py-2 rounded-xl text-center border border-blue-100 min-w-[100px]">
              <p className="text-[10px] font-bold text-blue-600 uppercase">Tổng Không ĐH</p>
              <p className="text-xl font-black text-blue-700">{factoryStats.noOrder}</p>
            </div>
          </div>
        </header>
        {renderDashboard()}
      </main>
    </div>
  );
};

