                <button 
                  key={area}
                  onClick={() => setSelectedArea(area as any)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-black transition-all ${selectedArea === area ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}
