import React, { useState } from 'react';
import { Machine, DowntimeEvent, MachineStatus } from '../types';

interface MaintenanceDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const MaintenanceDashboard: React.FC<MaintenanceDashboardProps> = ({ machines, events, onUpdateStatus }) => {
  const [notes, setNotes] = useState<Record<string, string>>({});

  const activeEvents = events.filter(e => !e.endTime);

  const maintenancePending = machines.filter(m => {
    if (m.status !== MachineStatus.STOPPED) return false;
    const event = activeEvents.find(e => e.machineId === m.id);
    return event && !event.isPlanned;
  });

  const handleResolve = (machineId: string) => {
    onUpdateStatus(machineId, MachineStatus.RUNNING);
    setNotes(prev => {
      const newNotes = { ...prev };
      delete newNotes[machineId];
      return newNotes;
    });
  };

  return (
    <div className="space-y-8">
      <div className="bg-blue-50 border-l-4 border-blue-400 p-4 rounded-r-xl flex justify-between items-center">
        <div>
          <h3 className="text-blue-800 font-bold flex items-center gap-2 text-lg">
            <span>🔧</span> PHÒNG KỸ THUẬT: MÁY ĐANG DỪNG SỰ CỐ ({maintenancePending.length})
          </h3>
          <p className="text-blue-700 text-sm">Danh sách các máy gặp sự cố kỹ thuật cần xử lý ngay.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {maintenancePending.map(machine => {
          const event = activeEvents.find(e => e.machineId === machine.id);
          const currentNotes = notes[machine.id] || '';

          return (
            <div key={machine.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col animate-in fade-in slide-in-from-bottom-4">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="text-2xl font-black text-slate-800">{machine.code}</h4>
                  <p className="text-xs text-slate-400 font-bold uppercase">{machine.brand} | {machine.capacity}T</p>
                </div>
                <div className="flex flex-col items-end">
                  <span className="bg-red-500 text-white px-3 py-1 rounded-full text-[10px] font-black uppercase shadow-sm">
                    Sự Cố Kỹ Thuật
                  </span>
                </div>
              </div>

              <div className="mb-6 p-4 bg-slate-50 rounded-2xl border border-slate-100 flex-1">
                <div className="flex justify-between items-center mb-2">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Lý do báo dừng</p>
                  <p className="text-[10px] font-mono font-bold text-red-400">
                    {event ? new Date(event.startTime).toLocaleTimeString() : '--:--'}
                  </p>
                </div>
                <p className="text-slate-800 font-black text-lg leading-tight">
                  {machine.currentDowntimeReason || 'Yêu cầu kiểm tra'}
                </p>
                <div className="mt-4 pt-4 border-t border-slate-200/50">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Nhật ký xử lý (Kỹ thuật)</p>
                   <textarea 
                    value={currentNotes}
                    onChange={(e) => setNotes({...notes, [machine.id]: e.target.value})}
                    placeholder="Nhập nội dung đã xử lý..."
                    className="w-full p-3 text-sm border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-white min-h-[80px]"
                   />
                </div>
              </div>

              <button 
                onClick={() => handleResolve(machine.id)}
                className="w-full bg-slate-900 hover:bg-green-600 text-white font-black py-4 rounded-2xl transition-all shadow-lg hover:shadow-green-200 flex items-center justify-center gap-2 group"
              >
                <span className="text-lg group-hover:scale-125 transition-transform">✅</span>
                BÁO CÁO ĐÃ SỬA XONG
              </button>
            </div>
          );
        })}

        {maintenancePending.length === 0 && (
          <div className="col-span-full py-20 text-center bg-white rounded-3xl border-2 border-dashed border-slate-200">
            <div className="text-5xl mb-4">✨</div>
            <p className="text-slate-500 font-bold text-lg">Hệ thống vận hành ổn định.</p>
            <p className="text-slate-400 text-sm">Hiện tại không có yêu cầu hỗ trợ kỹ thuật.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaintenanceDashboard;

import React, { useState } from 'react';
import { Machine, DowntimeEvent, MachineStatus, MachineBrand, MachineType } from '../types';

interface TeamLeaderDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
  onUpdateMachine: (machineId: string, updates: Partial<Machine>) => void;
}

const TeamLeaderDashboard: React.FC<TeamLeaderDashboardProps> = ({ machines, events, onUpdateStatus, onUpdateMachine }) => {
  const [editingMachine, setEditingMachine] = useState<Machine | null>(null);
  const [newCode, setNewCode] = useState('');
  const [newBrand, setNewBrand] = useState<MachineBrand>(MachineBrand.CLF);
  const [newType, setNewType] = useState<MachineType>(MachineType.INJECTION);
  const [newCapacity, setNewCapacity] = useState<number>(0);

  const openEditModal = (machine: Machine) => {
    setEditingMachine(machine);
    setNewCode(machine.code);
    setNewBrand(machine.brand);
    setNewType(machine.type);
    setNewCapacity(machine.capacity);
  };

  const handleSave = () => {
    if (editingMachine && newCode.trim()) {
      onUpdateMachine(editingMachine.id, {
        code: newCode.trim(),
        brand: newBrand,
        type: newType,
        capacity: newCapacity
      });
      setEditingMachine(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
          <h3 className="font-bold text-slate-800 uppercase">Bảng Điều Phối Của Trưởng Ca</h3>
          <div className="text-xs font-medium text-slate-500 italic">* Quản lý danh sách thiết bị và trạng thái vận hành</div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-400 text-xs font-bold uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4">Mã Máy</th>
                <th className="px-6 py-4">Cấu Hình</th>
                <th className="px-6 py-4">Trạng Thái</th>
                <th className="px-6 py-4">Lý Do Dừng</th>
                <th className="px-6 py-4">Thời Gian</th>
                <th className="px-6 py-4">Thao Tác</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {machines.map(machine => {
                const activeEvent = events.find(e => e.machineId === machine.id && !e.endTime);
                let duration = '0m';
                if (activeEvent) {
                  const diff = Math.floor((Date.now() - activeEvent.startTime) / 60000);
                  duration = `${diff}m`;
                }

                return (
                  <tr key={machine.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <div className="font-black text-slate-800 text-lg">{machine.code}</div>
                        <button 
                          onClick={() => openEditModal(machine)}
                          className="p-1 hover:bg-blue-50 text-blue-400 hover:text-blue-600 rounded transition-colors"
                        >
                          ✏️
                        </button>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                       <div className="flex flex-col gap-1">
                          <span className={`w-fit px-2 py-0.5 rounded text-[9px] font-black ${machine.type === MachineType.INJECTION ? 'bg-blue-100 text-blue-700' : 'bg-purple-100 text-purple-700'}`}>
                            {machine.type === MachineType.INJECTION ? 'MÁY ÉP' : 'MÁY THỔI'}
                          </span>
                          <span className="text-sm font-bold text-slate-600">{machine.brand} - {machine.capacity}T</span>
                       </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${
                        machine.status === MachineStatus.RUNNING 
                        ? 'bg-green-100 text-green-700' 
                        : 'bg-red-100 text-red-700'
                      }`}>
                        {machine.status === MachineStatus.RUNNING ? 'Chạy' : 'Dừng'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-slate-600 font-medium">
                      {machine.currentDowntimeReason || '-'}
                    </td>
                    <td className="px-6 py-4 text-sm font-mono font-bold text-slate-700">
                      {machine.status === MachineStatus.STOPPED ? duration : '-'}
                    </td>
                    <td className="px-6 py-4">
                      <button className="p-2 hover:bg-slate-100 rounded-lg transition-all text-lg">🕒</button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {editingMachine && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 bg-slate-50">
              <h3 className="text-xl font-black text-slate-800">Hiệu chỉnh máy</h3>
              <p className="text-slate-500 text-sm font-medium">Trưởng ca cập nhật thông tin thiết bị</p>
            </div>
            <div className="p-6 space-y-6">
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Mã Máy (Code)</label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-bold text-lg text-slate-700"
                  value={newCode}
                  onChange={(e) => setNewCode(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 uppercase mb-2 tracking-widest">Tải Trọng (Tấn)</label>
                <input 
                  type="number" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-slate-700"
                  value={newCapacity}
                  onChange={(e) => setNewCapacity(Number(e.target.value))}
                />
              </div>
            </div>
            <div className="p-6 border-t border-slate-100 bg-slate-50 flex gap-3">
              <button onClick={() => setEditingMachine(null)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-50 transition-all">Hủy</button>
              <button onClick={handleSave} className="flex-1 py-3 bg-slate-900 text-white rounded-xl font-bold hover:bg-black shadow-lg transition-all">Lưu</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default TeamLeaderDashboard;

import React, { useState, useMemo } from 'react';
import { Machine, MachineStatus, MachineType, DOWNTIME_REASONS } from '../types';

interface OperatorDashboardProps {
  machines: Machine[];
  onUpdateStatus: (machineId: string, status: MachineStatus, reason?: string) => void;
}

const OperatorDashboard: React.FC<OperatorDashboardProps> = ({ machines, onUpdateStatus }) => {
  const [filterType, setFilterType] = useState<MachineType | 'ALL'>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedMachine, setSelectedMachine] = useState<Machine | null>(null);
  const [showReasonModal, setShowReasonModal] = useState(false);

  const filteredMachines = useMemo(() => {
    return machines.filter(m => {
      const matchesType = filterType === 'ALL' || m.type === filterType;
      const matchesSearch = m.code.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesType && matchesSearch;
    });
  }, [machines, filterType, searchQuery]);

  const handleMachineClick = (machine: Machine) => {
    setSelectedMachine(machine);
    if (machine.status === MachineStatus.RUNNING) {
      setShowReasonModal(true);
    } else {
      onUpdateStatus(machine.id, MachineStatus.RUNNING);
    }
  };

  const selectReason = (reason: string) => {
    if (selectedMachine) {
      onUpdateStatus(selectedMachine.id, MachineStatus.STOPPED, reason);
      setShowReasonModal(false);
      setSelectedMachine(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row gap-4 items-center bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex bg-slate-100 p-1 rounded-lg">
          <button 
            onClick={() => setFilterType('ALL')}
            className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === 'ALL' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}
          >
            Tất cả ({machines.length})
          </button>
          <button onClick={() => setFilterType(MachineType.INJECTION)} className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === MachineType.INJECTION ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>Máy Ép</button>
          <button onClick={() => setFilterType(MachineType.BLOWING)} className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${filterType === MachineType.BLOWING ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500'}`}>Máy Thổi</button>
        </div>
        <div className="flex-1 w-full relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 font-bold">🔍</span>
          <input 
            type="text" 
            placeholder="NV vận hành tìm mã máy (vd: CLF2k, JAD450...)"
            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 2xl:grid-cols-7 gap-4">
        {filteredMachines.map((machine) => {
          const isPlanned = machine.currentDowntimeReason === 'Không Đơn Hàng' || machine.currentDowntimeReason === 'Không đơn hàng';
          return (
            <button
              key={machine.id}
              onClick={() => handleMachineClick(machine)}
              className={`flex flex-col items-center justify-center p-5 rounded-2xl border-2 transition-all active:scale-95 shadow-sm min-h-[140px] ${
                machine.status === MachineStatus.RUNNING 
                ? 'bg-white border-slate-100 hover:border-green-400' 
                : isPlanned 
                  ? 'bg-blue-50 border-blue-200 hover:border-blue-500 shadow-blue-100'
                  : 'bg-red-50 border-red-200 hover:border-red-500 shadow-red-100'
              }`}
            >
              <div className="flex items-center gap-1.5 mb-2">
                 <div className={`w-3 h-3 rounded-full ${machine.status === MachineStatus.RUNNING ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.6)]' : isPlanned ? 'bg-blue-500' : 'bg-red-500 animate-pulse'}`}></div>
                 <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{machine.type === MachineType.INJECTION ? 'Máy Ép' : 'Máy Thổi'}</span>
              </div>
              <h3 className={`text-lg font-black leading-tight tracking-tight text-center ${machine.status === MachineStatus.RUNNING ? 'text-slate-800' : isPlanned ? 'text-blue-700' : 'text-red-700'}`}>{machine.code}</h3>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">{machine.brand} {machine.capacity}T</p>
              {machine.status === MachineStatus.STOPPED && (
                <div className={`mt-3 w-full truncate text-[10px] font-black py-1.5 px-2 rounded-lg text-center uppercase tracking-tight shadow-inner ${isPlanned ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'}`}>
                  {machine.currentDowntimeReason || 'ĐANG DỪNG'}
                </div>
              )}
            </button>
          );
        })}
      </div>

      {showReasonModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl scale-in-center">
            <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-black text-slate-800 tracking-tight uppercase">Báo cáo dừng máy: {selectedMachine?.code}</h2>
                <p className="text-slate-500 text-sm font-medium">NV Vận hành chọn lý do chính xác để ghi nhận OEE</p>
              </div>
              <button onClick={() => setShowReasonModal(false)} className="text-slate-400 text-3xl hover:text-slate-600 font-light">&times;</button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-50/20">
              {DOWNTIME_REASONS.map((group) => (
                <div key={group.category} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                  <h4 className="text-[10px] font-black uppercase tracking-widest mb-3 border-b border-slate-50 pb-2 text-slate-400">{group.category}</h4>
                  <div className="grid grid-cols-1 gap-2">
                    {group.reasons.map(reason => (
                      <button
                        key={reason}
                        onClick={() => selectReason(reason)}
                        className={`w-full text-left p-3.5 rounded-xl border transition-all font-black text-xs active:scale-95 ${reason === 'Không Đơn Hàng' || reason === 'Không đơn hàng' ? 'border-blue-200 bg-blue-50/50 hover:border-blue-500 text-blue-700' : 'border-slate-100 hover:border-red-400 hover:bg-red-50 text-slate-700'}`}
                      >
                        {reason}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
            <div className="p-6 border-t border-slate-100 flex justify-end bg-slate-50">
               <button onClick={() => setShowReasonModal(false)} className="px-8 py-3.5 bg-white border border-slate-200 text-slate-600 rounded-xl font-black uppercase text-xs hover:bg-slate-100">Hủy</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

