import React, { useState, useMemo } from 'react';
import { Machine, DowntimeEvent } from '../types';

interface HistoryDashboardProps {
  machines: Machine[];
  events: DowntimeEvent[];
}

const HistoryDashboard: React.FC<HistoryDashboardProps> = ({ machines, events }) => {
  const [dateFilter, setDateFilter] = useState(new Date().toISOString().split('T')[0]);
  const [shiftFilter, setShiftFilter] = useState<'ALL' | '1' | '2' | '3'>('ALL');
  const [searchCode, setSearchCode] = useState('');

  const getShift = (timestamp: number) => {
    const hour = new Date(timestamp).getHours();
    if (hour >= 6 && hour < 14) return '1';
    if (hour >= 14 && hour < 22) return '2';
    return '3';
  };

  const filteredHistory = useMemo(() => {
    return events.filter(event => {
      const eventDate = new Date(event.startTime).toISOString().split('T')[0];
      const matchesDate = eventDate === dateFilter;
      const matchesShift = shiftFilter === 'ALL' || getShift(event.startTime) === shiftFilter;
      const machine = machines.find(m => m.id === event.machineId);
      const matchesSearch = !searchCode || machine?.code.toLowerCase().includes(searchCode.toLowerCase());

      return matchesDate && matchesShift && matchesSearch;
    }).sort((a, b) => b.startTime - a.startTime);
  }, [events, dateFilter, shiftFilter, searchCode, machines]);

  const exportToExcel = () => {
    // Tiêu đề cột
    const headers = ["Ngày", "Ca", "Mã Máy", "Lý Do Gián Đoạn", "Bắt Đầu", "Kết Thúc", "Số Phút", "Loại"];

    // Sử dụng ký tự Tab (\t) là cách an toàn nhất để Excel tự tách cột
    const DELIMITER = "\t";

    // Chuyển dữ liệu thành mảng các dòng
    const rows = filteredHistory.map(e => {
      const m = machines.find(mac => mac.id === e.machineId);
      const duration = e.endTime 
        ? Math.round((e.endTime - e.startTime) / 60000) 
        : Math.round((Date.now() - e.startTime) / 60000);

      return [
        new Date(e.startTime).toLocaleDateString('vi-VN'),
        getShift(e.startTime),
        m?.code || '',
        (e.reason || ''),
        new Date(e.startTime).toLocaleTimeString('vi-VN'),
        e.endTime ? new Date(e.endTime).toLocaleTimeString('vi-VN') : 'Đang chạy',
        duration,
        e.isPlanned ? "Kế hoạch" : "Sự cố"
      ];
    });

    // Tạo nội dung văn bản với các cột cách nhau bằng Tab
    const content = [headers, ...rows].map(row => row.join(DELIMITER)).join("\r\n");

    // Sử dụng BOM (Byte Order Mark) để Excel nhận diện UTF-8
    const BOM = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const blob = new Blob([BOM, content], { type: 'text/excel;charset=utf-8;' });

    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    // Lưu dưới đuôi .xls để Excel mở thẳng và tự nhận diện định dạng Tab-Separated
    link.setAttribute("download", `Lich_su_gian_doan_${dateFilter}.xls`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
