const App: React.FC = () => {
  const [userRole, setUserRole] = useState<Role>(Role.OPERATOR);
  const [selectedArea, setSelectedArea] = useState<1 | 2 | 3 | 'ALL'>('ALL');
  const [machines, setMachines] = useState<Machine[]>(generateAllMachines());
  const [events, setEvents] = useState<DowntimeEvent[]>([]);
  const [showHistory, setShowHistory] = useState(false);
  const [showQuickOrderModal, setShowQuickOrderModal] = useState(false);

  const filteredMachines = useMemo(() => {
    if (selectedArea === 'ALL') return machines;
    return machines.filter(m => m.area === selectedArea);
  }, [machines, selectedArea]);

  const factoryStats = useMemo(() => {
    const running = machines.filter(m => m.status === MachineStatus.RUNNING).length;
    const stopped = machines.filter(m => 
      m.status === MachineStatus.STOPPED && !PLANNED_REASONS.includes(m.currentDowntimeReason || '')
    ).length;
    const noOrder = machines.filter(m => 
      m.status === MachineStatus.STOPPED && PLANNED_REASONS.includes(m.currentDowntimeReason || '')
    ).length;
    return { total: machines.length, running, stopped, noOrder };
  }, [machines]);

  const handleUpdateMachineStatus = (machineId: string, status: MachineStatus, reason?: string) => {
    setMachines(prev => prev.map(m => m.id === machineId ? { ...m, status, currentDowntimeReason: reason } : m));
    if (status === MachineStatus.STOPPED && reason) {
      setEvents(prev => [...prev, {
        id: Math.random().toString(36).substr(2, 9),
        machineId,
        startTime: Date.now(),
        reason,
        category: 'Hệ thống',
        isPlanned: PLANNED_REASONS.includes(reason)
      }]);
    } else if (status === MachineStatus.RUNNING) {
      setEvents(prev => prev.map(e => (e.machineId === machineId && !e.endTime) ? { ...e, endTime: Date.now() } : e));
    }
  };

  const handleQuickNoOrder = (machineIds: string[]) => {
    machineIds.forEach(id => handleUpdateMachineStatus(id, MachineStatus.STOPPED, 'Không có đơn hàng'));
    setShowQuickOrderModal(false);
  };

  const handleUpdateMachineDetails = (machineId: string, updates: Partial<Machine>) => {
    setMachines(prev => prev.map(m => m.id === machineId ? { ...m, ...updates } : m));
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900">
      <Sidebar userRole={userRole} onRoleChange={setUserRole} onShowHistory={() => setShowHistory(!showHistory)} isHistoryActive={showHistory} />
      <main className="flex-1 overflow-y-auto p-3 md:p-6">
        <header className="mb-4 md:mb-6 bg-white p-4 md:p-5 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex flex-col gap-4">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-3">
              <div>
                <h1 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight">
                  <span className="text-blue-600 uppercase">
                    {showHistory ? 'Lịch Sử' : (selectedArea === 'ALL' ? 'Toàn Nhà Máy' : `Khu Vực ${selectedArea}`)}
                  </span>
                </h1>
                <p className="text-slate-400 text-[10px] md:text-sm font-bold uppercase tracking-wider">Hệ thống giám sát SmartMolding</p>
              </div>

              <div className="flex items-center gap-2 overflow-x-auto pb-1 no-scrollbar">
                {[1, 2, 3, 'ALL'].map(area => (
                  <button 
                    key={area}
                    onClick={() => setSelectedArea(area as any)}
                    className={`whitespace-nowrap px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${selectedArea === area ? 'bg-blue-600 text-white shadow-md shadow-blue-100' : 'bg-slate-100 text-slate-500'}`}
                  >
                    {area === 'ALL' ? 'TẤT CẢ' : `KHU ${area}`}
                  </button>
                ))}
              </div>
            </div>

            {!showHistory && (
              <div className="flex items-center gap-2 overflow-x-auto pb-2 no-scrollbar">
                {[
                  { label: 'TỔNG', val: factoryStats.total, color: 'slate' },
                  { label: 'CHẠY', val: factoryStats.running, color: 'green' },
                  { label: 'LỖI', val: factoryStats.stopped, color: 'red' },
                  { label: 'DỪNG KH', val: factoryStats.noOrder, color: 'blue' }
                ].map(stat => (
                  <div key={stat.label} className={`bg-${stat.color}-50 px-3 py-2 rounded-xl text-center border border-${stat.color}-100 min-w-[75px] md:min-w-[100px] flex-shrink-0`}>
                    <p className={`text-[8px] md:text-[10px] font-bold text-${stat.color}-600 uppercase`}>{stat.label}</p>
                    <p className={`text-sm md:text-xl font-black text-${stat.color}-700`}>{stat.val}</p>
                  </div>
                ))}

                {(userRole === Role.TEAM_LEADER || userRole === Role.MANAGER) && (
                  <button 
                    onClick={() => setShowQuickOrderModal(true)}
                    className="ml-auto flex-shrink-0 bg-blue-100 text-blue-700 h-full px-4 rounded-xl text-[10px] font-black uppercase hover:bg-blue-200 transition-all border border-blue-200"
                  >
                    📦 CẬP NHẬT ĐƠN HÀNG
                  </button>
                )}
              </div>
            )}
          </div>
        </header>

        <div className="max-w-full overflow-x-hidden">
          {showHistory ? (
            <HistoryDashboard machines={machines} events={events} />
          ) : (
            <>
              {userRole === Role.OPERATOR && <OperatorDashboard machines={filteredMachines} onUpdateStatus={handleUpdateMachineStatus} />}
              {userRole === Role.MANAGER && <ManagerDashboard machines={filteredMachines} events={events} onUpdateMachine={handleUpdateMachineDetails} />}
              {userRole === Role.MAINTENANCE && <MaintenanceDashboard machines={filteredMachines} events={events} onUpdateStatus={handleUpdateMachineStatus} />}
              {userRole === Role.TEAM_LEADER && <TeamLeaderDashboard machines={filteredMachines} events={events} onUpdateStatus={handleUpdateMachineStatus} onUpdateMachine={handleUpdateMachineDetails} />}
            </>
          )}
        </div>

        {showQuickOrderModal && (
          <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-sm flex items-end md:items-center justify-center p-0 md:p-4 z-[100]">
            <div className="bg-white rounded-t-3xl md:rounded-3xl w-full max-w-4xl max-h-[85vh] overflow-hidden flex flex-col shadow-2xl">
              <div className="p-4 md:p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                <h2 className="text-lg md:text-xl font-black text-slate-800 uppercase">Dừng máy nhanh (Không đơn hàng)</h2>
                <button onClick={() => setShowQuickOrderModal(false)} className="text-slate-400 text-2xl px-2">&times;</button>
              </div>
              <div className="flex-1 overflow-y-auto p-4 md:p-6">
                <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-2">
                  {machines.filter(m => m.status === MachineStatus.RUNNING).map(m => (
                    <button 
                      key={m.id}
                      onClick={() => handleQuickNoOrder([m.id])}
                      className="p-2 border border-slate-200 rounded-lg hover:bg-blue-50 hover:border-blue-400 transition-all text-center group"
                    >
                      <p className="text-[10px] font-black text-slate-700 truncate">{m.code}</p>
                      <p className="text-[7px] text-slate-400 font-bold uppercase">{m.capacity}T</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default App;

